script.text:
      &OutlineEntry;
      /* <flatten type="Javascript"> */
function active$VoucherFilter$(sender) {
  sender.add_onResponseComplete(on$Filter$ResponseComplete);
  changeLookupReadonly(sender, 'ma_dvcs', true);
}
function close$VoucherFilter$(sender) {try {sender.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}}
function on$Filter$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      var g = f.grid, k = [];
      g._p = f.getItemValue('ky'), g._y = f.getItemValue('nam'), g._u = f.getItemValue('ma_dvcs');
      g._alterTitle = [null, [['%s1', $func.trim(g._p.toString()), true], ['%s2', $func.trim(g._y.toString()), true]]];

      Array.add(k, {Name: 'ky', Opr: '=', Value: g._p, Type: 'Decimal', Ignore: false});
      Array.add(k, {Name: 'nam', Opr: '=', Value: g._y, Type: 'Decimal', Ignore: false});
      if (f.getItemValue('ma_dvcs')) Array.add(k, {Name: "dbo.ff_InList(ma_dvcs,'" + g._u + "')", Opr: '=', Value: 1, Type: 'String', Ignore: false});
      g.set_externalKey(k);
      g._queryFilterString = getQueryFilterString(f, 'ky, nam');
      g._$k = g._$c = g._$r = [];
      break;
    default:
      break;
  }
}
function getQueryFilterString(f, s) {
  var q = '', a = s.split(',');
  for (var i = 0; i < a.length; i++) {
    var c = $func.trim(a[i]), o = f.getItem(c), v = (o ? f.getItemValue(c) : c);
    q += String.fromCharCode(253);
    if (o) {
      switch (o.field.Type) {
        case 'DateTime':
          q += $func.formatDateOrder(v);
          break;
        case 'Boolean':
          q += (v ? '1' : '0');
          break;
        case 'Decimal';
          q += v.toString();
          break;
        default:
          q += $func.replace(v, '\'', String.fromCharCode(252));
          break;
      }
    } else q += $func.replace(v, '\'', String.fromCharCode(252));
  }
  return q;
}
/* </flatten> */
